=DECLARE
   p0_  VARCHAR2(32000) := '';
   p1_  FLOAT;
   p2_  VARCHAR2(32000) := '{{ $json.ORDER_NO }}';
   p3_  VARCHAR2(32000) := '{{ $json.RELEASE_NO }}';
   p4_  VARCHAR2(32000) := '{{ $json.SEQUENCE_NO }}';
   p5_  VARCHAR2(32000) := '1';
   p6_  VARCHAR2(32000) := 'Yes';
   p7_  VARCHAR2(32000) := 'No';
   p8_  VARCHAR2(32000) := 'Shop Order';
   p9_  FLOAT := NULL;
   p10_ VARCHAR2(32000) := '!
$CONDITION_CODE=
$LOCATION_NO=FG
$LOT_BATCH_NO={{ $json.LOTE }}
$WAIV_DEV_REJ_NO=
$EXPIRATION_DATE=
$AVAILABILITY_CONTROL_ID=
$CATCH_QTY=0
$RESERVED_QTY={{ $json.RESERVED_QTY }}
';
   p11_ VARCHAR2(32000) := 'No';
   p12_ VARCHAR2(32000) := 'TRUE';
BEGIN
   SELECT IFSAPP.Inventory_Putaway_Manager_API.Get_Next_Putaway_Event_Id INTO p1_ FROM DUAL;
   IFSAPP.Shop_Ord_Util_API.Receive_Lots_In_Message__(p0_, p1_, p2_, p3_, p4_, p5_, p6_, p7_, p8_, p9_, p10_, p11_, p12_);
END;

=DECLARE
   p0_ VARCHAR2(32000) := '{{ $json.ORDER_NO }}';
   p1_ VARCHAR2(32000) := '{{ $json.RELEASE_NO }}';
   p2_ VARCHAR2(32000) := '{{ $json.SEQUENCE_NO }}';
BEGIN
   IFSAPP.Shop_Ord_API.Close_So_Under_Issue('AMO', p0_, p1_, p2_);
END;
